import numpy as npimport numpy.testing as nptfrom knn_package import KNN#test 1:def test_train_and_predict():    model = KNN(k = 2)        X = np.array([                [3, 4],                [4, 3],                [7, 6],                [10, 9]])    y = np.array([1, 1, 2, 2])        model.fit(X, y)        X_hat = np.array([                    [3, 4],                    [10, 10],                    [7, 8],                    [1, 2]])        y_hat = model.predict(X_hat)        expected = np.array([1, 2, 2, 1])    labels = [1, 2]        #sub-test 1: check output size    assert len(y_hat) == 4        #sub-test 2: check the labels are in correct domain    assert np.isin(y_hat, labels).all()        #sub-test 3: exact values comparison    npt.assert_array_equal(y_hat, expected)